def batch_convert(input_files, output_dir, output_format):
    """
    Batch convert multiple files to a specified format.
    
    Args:
        input_files (list): List of input file paths.
        output_dir (str): Directory to save converted files.
        output_format (str): Target format.
    
    Returns:
        list: List of result dictionaries for each conversion.
    """
    os.makedirs(output_dir, exist_ok=True)
    results = []
    
    for input_file in input_files:
        input_basename = Path(input_file).stem
        output_file = os.path.join(output_dir, f"{input_basename}.{output_format}")
        
        print(f"Converting: {input_file} -> {output_file}")
        result = convertDocument(input_file, output_file, output_format)
        result['input_file'] = input_file
        results.append(result)
        
        if result['success']:
            print(f"  ✓ {result['message']}")
        else:
            print(f"  ✗ {result['message']}")
    
    successful = sum(1 for r in results if r['success'])
    print(f"\nBatch conversion complete: {successful}/{len(results)} successful")
    
    return results


